/*
 * Weekly Iraq Situation Report UI
 *
 * The weekly report is now generated by GitHub Actions with OpenAI, not by
 * exposing an API key in the browser. This UI downloads the latest AI-created
 * report and shows the workflow instructions when no report exists yet.
 */
(() => {
  const LATEST_DOCX_URL = "./reports/latest.docx";
  const LATEST_META_URL = "./reports/latest.json";

  function boot() {
    const btn = document.querySelector("#weeklyReportBtn");
    if (!btn) return;
    injectPanel();
    btn.addEventListener("click", openPanel);
  }

  function injectPanel() {
    if (document.querySelector("#weeklyReportOverlay")) return;

    const overlay = document.createElement("div");
    overlay.id = "weeklyReportOverlay";
    overlay.className = "weekly-report-overlay";
    overlay.setAttribute("aria-hidden", "true");
    overlay.innerHTML = `
      <section class="weekly-report-modal" role="dialog" aria-modal="true" aria-labelledby="weeklyReportTitle">
        <header class="weekly-report-head">
          <div>
            <h2 id="weeklyReportTitle">AI 주간 보고서</h2>
            <p id="weeklyReportDesc">GitHub Actions에서 OpenAI가 최근 7일치 기사·COM·SNS 데이터를 판단해 작성한 Word 보고서를 다운로드합니다.</p>
          </div>
          <button class="weekly-report-close" type="button" aria-label="닫기">×</button>
        </header>
        <div id="weeklyReportBody" class="weekly-report-body">
          <div class="weekly-report-loading">최신 AI 주간보고서 상태를 확인하는 중입니다.</div>
        </div>
        <footer class="weekly-report-foot">
          <p id="weeklyReportNote" class="weekly-report-note">보고서가 없으면 GitHub Actions에서 Generate AI Weekly Report workflow를 먼저 실행하세요.</p>
          <div class="weekly-report-actions">
            <button id="weeklyRefreshBtn" class="ghost-btn" type="button">상태 새로고침</button>
            <a id="weeklyDownloadLatestBtn" class="primary-btn" href="${LATEST_DOCX_URL}" download>최신 Word 다운로드</a>
          </div>
        </footer>
      </section>
    `;

    document.body.appendChild(overlay);

    overlay.querySelector(".weekly-report-close").addEventListener("click", closePanel);
    overlay.addEventListener("click", (event) => {
      if (event.target === overlay) closePanel();
    });

    overlay.querySelector("#weeklyRefreshBtn").addEventListener("click", renderPanel);
  }

  async function openPanel() {
    const overlay = document.querySelector("#weeklyReportOverlay");
    overlay.classList.add("is-open");
    overlay.setAttribute("aria-hidden", "false");
    await renderPanel();
  }

  function closePanel() {
    const overlay = document.querySelector("#weeklyReportOverlay");
    overlay.classList.remove("is-open");
    overlay.setAttribute("aria-hidden", "true");
  }

  async function renderPanel() {
    const body = document.querySelector("#weeklyReportBody");
    const note = document.querySelector("#weeklyReportNote");
    const downloadBtn = document.querySelector("#weeklyDownloadLatestBtn");

    body.innerHTML = `<div class="weekly-report-loading">최신 AI 주간보고서 상태를 확인하는 중입니다.</div>`;
    note.textContent = "보고서 생성은 GitHub Actions에서 실행되며, OpenAI API 키는 브라우저에 노출되지 않습니다.";
    downloadBtn.classList.add("is-disabled");
    downloadBtn.setAttribute("aria-disabled", "true");
    downloadBtn.addEventListener("click", preventDisabledClick);

    const meta = await fetchMeta();
    const exists = await fileExists(LATEST_DOCX_URL);

    if (!exists) {
      body.innerHTML = `
        <div class="weekly-report-empty">
          <strong>아직 생성된 AI 주간보고서가 없습니다.</strong><br><br>
          GitHub 저장소에서 아래 순서로 실행하세요.<br>
          <code>Actions → Generate AI Weekly Report → Run workflow</code><br><br>
          실행이 완료되면 <code>reports/latest.docx</code>가 생성되고, 이 버튼에서 다운로드할 수 있습니다.
        </div>
      `;
      note.textContent = "최초 1회 생성 후부터 최신 Word 보고서를 다운로드할 수 있습니다.";
      return;
    }

    downloadBtn.classList.remove("is-disabled");
    downloadBtn.removeAttribute("aria-disabled");
    downloadBtn.removeEventListener("click", preventDisabledClick);
    downloadBtn.href = `${LATEST_DOCX_URL}?v=${Date.now()}`;

    body.innerHTML = `
      <div class="weekly-report-summary">
        <div class="weekly-report-summary-card">
          <span>보고서 기간</span>
          <strong>${escapeHtml(formatPeriod(meta))}</strong>
        </div>
        <div class="weekly-report-summary-card">
          <span>생성일</span>
          <strong>${escapeHtml(formatGeneratedAt(meta.generatedAt))}</strong>
        </div>
        <div class="weekly-report-summary-card">
          <span>AI 모델</span>
          <strong>${escapeHtml(meta.model || "OpenAI")}</strong>
        </div>
        <div class="weekly-report-summary-card">
          <span>참고 항목</span>
          <strong>${Number(meta.itemCount || 0).toLocaleString("ko-KR")}건</strong>
        </div>
      </div>
      <div class="weekly-report-empty">
        <strong>${escapeHtml(meta.title || "건설, 이라크 주간 종합 상황보고")}</strong><br><br>
        최신 AI 생성 보고서가 준비되어 있습니다. 아래 <b>최신 Word 다운로드</b> 버튼을 누르세요.<br>
        보고서 품질이 부족하면 뉴스 수집 workflow를 먼저 실행한 뒤 다시 <b>Generate AI Weekly Report</b>를 실행하면 됩니다.
      </div>
    `;
  }

  function preventDisabledClick(event) {
    const link = event.currentTarget;
    if (link.classList.contains("is-disabled")) {
      event.preventDefault();
    }
  }

  async function fetchMeta() {
    try {
      const res = await fetch(`${LATEST_META_URL}?v=${Date.now()}`, { cache: "no-store" });
      if (!res.ok) return {};
      return await res.json();
    } catch {
      return {};
    }
  }

  async function fileExists(url) {
    try {
      const res = await fetch(`${url}?v=${Date.now()}`, { method: "HEAD", cache: "no-store" });
      if (res.ok) return true;
    } catch {}

    try {
      const res = await fetch(`${url}?v=${Date.now()}`, { cache: "no-store" });
      return res.ok;
    } catch {
      return false;
    }
  }

  function formatPeriod(meta = {}) {
    if (meta.periodStart && meta.periodEnd) {
      return `${meta.periodStart} ~ ${meta.periodEnd}`;
    }
    return "최근 7일";
  }

  function formatGeneratedAt(value) {
    if (!value) return "확인 필요";
    const date = new Date(value);
    if (Number.isNaN(date.getTime())) return value;
    return new Intl.DateTimeFormat("ko-KR", {
      year: "numeric",
      month: "2-digit",
      day: "2-digit",
      hour: "2-digit",
      minute: "2-digit"
    }).format(date);
  }

  function escapeHtml(value = "") {
    return String(value)
      .replaceAll("&", "&amp;")
      .replaceAll("<", "&lt;")
      .replaceAll(">", "&gt;")
      .replaceAll('"', "&quot;")
      .replaceAll("'", "&#039;");
  }

  document.addEventListener("DOMContentLoaded", boot);
})();
